  private def sanitizeXML(xmlString: String): String = {
    val doctypePattern = "(?i)<!DOCTYPE[^>]*>".r
    val entityPattern = "(?i)<!ENTITY[^>]*>".r
    val cleaned = doctypePattern.replaceAllIn(xmlString, "")
    entityPattern.replaceAllIn(cleaned, "")
  }
  
  private def extractSettings(elem: Elem): ConfigurationSettings = {
    val directSettings = (elem \ "setting").map { node =>
      val key = (node \@ "key").trim
      val value = (node \@ "value").trim
      
      if (key.isEmpty) {
        throw new IllegalArgumentException("Setting key cannot be empty")
      }
      
      key -> value
    }.toMap
    
    val nestedConfigs = (elem \ "config").map { node =>
      val name = (node \@ "name").trim
      
      if (name.isEmpty) {
        throw new IllegalArgumentException("Config name cannot be empty")
      }
      
      name -> extractSettings(node.asInstanceOf[Elem])
    }.toMap
    
    ConfigurationSettings(directSettings, nestedConfigs)
  }
  
  def extractSetting(config: ConfigurationSettings, path: String): Option[String] = {
    if (path == null || path.trim.isEmpty) {
      return None
    }
    
    val parts = path.split("\\.").map(_.trim).filter(_.nonEmpty)
    
    if (parts.isEmpty) {
      return None
    }
    
    if (parts.length == 1) {
      config.settings.get(parts.head)
    } else {
      config.nestedConfigs.get(parts.head).flatMap { nestedConfig =>
        extractSetting(nestedConfig, parts.tail.mkString("."))
      }
    }
  }
  
  def getAllSettings(config: ConfigurationSettings, prefix: String = ""): Map[String, String] = {
    val currentPrefix = if (prefix.isEmpty) "" else prefix + "."
    
    val directSettings = config.settings.map { case (key, value) =>
      (currentPrefix + key) -> value
    }
    
    val nestedSettings = config.nestedConfigs.flatMap { case (name, nestedConfig) =>
      getAllSettings(nestedConfig, currentPrefix + name)
    }
    
    directSettings ++ nestedSettings
  }
  
  def validateConfiguration(config: ConfigurationSettings, requiredKeys: Set[String]): Either[ParseError, Unit] = {
