    }
  }
  
  def mergeConfigurations(base: ConfigurationSettings, override: ConfigurationSettings): ConfigurationSettings = {
    val mergedSettings = base.settings ++ override.settings
    
    val mergedNestedConfigs = (base.nestedConfigs.keySet ++ override.nestedConfigs.keySet).map { key =>
      val merged = (base.nestedConfigs.get(key), override.nestedConfigs.get(key)) match {
        case (Some(baseConfig), Some(overrideConfig)) =>
          mergeConfigurations(baseConfig, overrideConfig)
        case (Some(baseConfig), None) =>
          baseConfig
        case (None, Some(overrideConfig)) =>
          overrideConfig
        case (None, None) =>
          ConfigurationSettings(Map.empty)
      }
      key -> merged
    }.toMap
    
    ConfigurationSettings(mergedSettings, mergedNestedConfigs)
